const fs = await import('fs');
const path = await import('path');
const { pathToFileURL } = await import('url');
const candidates = [];
const home = process.env.HOME || '';
const marketplaceNames = ['revela', 'revela-local'];
candidates.push(path.resolve(process.cwd(), 'bin/revela.ts'));
const configPath = path.join(home, '.codex', 'config.toml');
if (fs.existsSync(configPath)) {
  const text = fs.readFileSync(configPath, 'utf-8');
  const sections = text.split(/\n(?=\s*\[)/);
  for (const marketplaceName of marketplaceNames) {
    const section = sections.find((item) => item.trimStart().startsWith(`[marketplaces.${marketplaceName}]`));
    const match = section?.match(/^\s*source\s*=\s*"([^"]+)"/m);
    if (match && !/^[a-z][a-z0-9+.-]*:\/\//i.test(match[1])) candidates.push(path.join(match[1], 'bin/revela.ts'));
  }
}
for (const marketplaceName of marketplaceNames) {
  candidates.push(path.join(home, '.codex', '.tmp', 'marketplaces', marketplaceName, 'bin/revela.ts'));
}
for (const marketplaceName of marketplaceNames) {
  const cacheRoot = path.join(home, '.codex', 'plugins', 'cache', marketplaceName, 'revela');
  if (fs.existsSync(cacheRoot)) {
    for (const version of fs.readdirSync(cacheRoot).sort().reverse()) candidates.push(path.join(cacheRoot, version, 'bin/revela.ts'));
  }
}
const cli = candidates.find((candidate) => fs.existsSync(candidate));
if (!cli) {
  console.error(`Could not locate Revela CLI. Checked: ${candidates.join(', ')}`);
  process.exit(1);
}
process.env.REVELA_CLI_COMMAND = 'mcp';
await import(pathToFileURL(cli).href);
